/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const m = grid.length;
    if (m === 0) return 0;
    const n = grid[0].length;
    if (n === 0) return 0;

    // The total number of steps is (m - 1) + (n - 1) = m + n - 2.
    // The length of any path is m + n - 1.
    // The problem constraint m * n <= 1000 is key.
    // However, the path length can be up to 2000 if m=1000, n=1, but since m*n <= 1000, 
    // the path length is at most around 2*sqrt(1000) approx 64-71.
    // Since we need the minimum XOR sum, this suggests dynamic programming or BFS/DFS with state.

    // The path length is fixed: L = m + n - 1.
    // A DP approach where dp[r][c] stores the set of all possible XOR sums to reach (r, c)
    // would be too slow because the set size can grow exponentially.

    // Since the maximum value in grid[i][j] is 1023 (10 bits), the XOR sum is also at most 1023.
    // This suggests that we can use the XOR sum as part of the DP state.

    // Let dp[r][c] be a set (or boolean array) representing all achievable XOR sums to reach (r, c).
    // Since the maximum XOR value is 1023, we can use a boolean array of size 1024.

    // dp[r][c][xor_sum] = true if xor_sum is achievable at (r, c).
    const MAX_XOR = 1024;

    // Initialize DP table. Using Map for sparse storage might be better if the reachable states are few,
    // but given the constraints, let's try the fixed size array first.
    // dp[r][c] will store an array/set of achievable XOR sums.
    const dp = Array(m).fill(0).map(() => 
        Array(n).fill(0).map(() => Array(MAX_XOR).fill(false))
    );

    // Base case: (0, 0)
    const initialXor = grid[0][0];
    dp[0][0][initialXor] = true;

    // Fill the DP table
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            const currentValue = grid[r][c];

            // Skip the base case as it's already handled
            if (r === 0 && c === 0) continue;

            // Calculate possible XOR sums arriving at (r, c)

            // 1. From above (r-1, c)
            if (r > 0) {
                for (let prevXor = 0; prevXor < MAX_XOR; prevXor++) {
                    if (dp[r - 1][c][prevXor]) {
                        const newXor = prevXor ^ currentValue;
                        dp[r][c][newXor] = true;
                    }
                }
            }

            // 2. From left (r, c-1)
            if (c > 0) {
                for (let prevXor = 0; prevXor < MAX_XOR; prevXor++) {
                    if (dp[r][c - 1][prevXor]) {
                        const newXor = prevXor ^ currentValue;
                        dp[r][c][newXor] = true;
                    }
                }
            }
        }
    }

    // Find the minimum XOR sum at the target cell (m-1, n-1)
    let minXor = MAX_XOR; // Initialize with a value larger than any possible XOR sum (1024)

    for (let xorSum = 0; xorSum < MAX_XOR; xorSum++) {
        if (dp[m - 1][n - 1][xorSum]) {
            if (xorSum < minXor) {
                minXor = xorSum;
            }
        }
    }

    return minXor;
}

